public class MaxSubarray {
    static int maxSum(int[] nums){int max=nums[0],curr=nums[0];for(int i=1;i<nums.length;i++){curr=Math.max(nums[i],curr+nums[i]);max=Math.max(max,curr);}return max;}
    public static void main(String[] a){System.out.println(maxSum(new int[]{-2,1,-3,4,-1,2,1,-5,4}));System.out.println(maxSum(new int[]{1}));System.out.println(maxSum(new int[]{5,4,-1,7,8}));System.out.println("Kadane: curr=max(num,curr+num). O(n) O(1). Zerodha P&L analysis.");}
}

public class StockProfit {
    static int maxProfit(int[] p){int minP=p[0],maxP=0;for(int i=1;i<p.length;i++){maxP=Math.max(maxP,p[i]-minP);minP=Math.min(minP,p[i]);}return maxP;}
    public static void main(String[] a){System.out.println(maxProfit(new int[]{7,1,5,3,6,4}));System.out.println(maxProfit(new int[]{7,6,4,3,1}));System.out.println("O(n) O(1) — track min price so far and max profit. Classic Zerodha trading problem.");}
}

import java.util.*;
public class BalancedParens {
    static boolean isValid(String s){Deque<Character> st=new ArrayDeque<>();for(char c:s.toCharArray()){if(c=='('||c=='['||c=='{')st.push(c);else{if(st.isEmpty())return false;char t=st.pop();if(c==')'&&t!='('||c==']'&&t!='['||c=='}'&&t!='{')return false;}}return st.isEmpty();}
    public static void main(String[] a){System.out.println(isValid("()[]{}"));System.out.println(isValid("(]"));System.out.println(isValid("{[()]}"));System.out.println("Stack pattern — O(n). Interview warm-up at every company.");}
}

import java.util.*;
public class DupWindow {
    static boolean hasDup(int[] nums,int k){Set<Integer> w=new HashSet<>();for(int i=0;i<nums.length;i++){if(w.contains(nums[i]))return true;w.add(nums[i]);if(w.size()>k)w.remove(nums[i-k]);}return false;}
    public static void main(String[] a){System.out.println(hasDup(new int[]{1,2,3,1},3));System.out.println(hasDup(new int[]{1,0,1,1},1));System.out.println(hasDup(new int[]{1,2,3,1,2,3},2));System.out.println("Sliding HashSet window O(n) O(k).");}
}

import java.util.*;
public class ThreeSum {
    static List<List<Integer>> threeSum(int[] nums){Arrays.sort(nums);List<List<Integer>> res=new ArrayList<>();for(int i=0;i<nums.length-2;i++){if(i>0&&nums[i]==nums[i-1])continue;int lo=i+1,hi=nums.length-1;while(lo<hi){int s=nums[i]+nums[lo]+nums[hi];if(s==0){res.add(Arrays.asList(nums[i],nums[lo],nums[hi]));while(lo<hi&&nums[lo]==nums[lo+1])lo++;while(lo<hi&&nums[hi]==nums[hi-1])hi--;lo++;hi--;}else if(s<0)lo++;else hi--;}}return res;}
    public static void main(String[] a){System.out.println(threeSum(new int[]{-1,0,1,2,-1,-4}));System.out.println("O(n²) — sort + two pointer. Skip duplicates at all 3 levels.");}
}

import java.util.*;
public class ProductExcept {
    static int[] productExceptSelf(int[] nums){int n=nums.length;int[] res=new int[n];res[0]=1;for(int i=1;i<n;i++)res[i]=res[i-1]*nums[i-1];int right=1;for(int i=n-1;i>=0;i--){res[i]*=right;right*=nums[i];}return res;}
    public static void main(String[] a){System.out.println(Arrays.toString(productExceptSelf(new int[]{1,2,3,4})));System.out.println(Arrays.toString(productExceptSelf(new int[]{-1,1,0,-3,3})));System.out.println("O(n) O(1) extra — prefix product then right product sweep.");}
}

public class JumpGame {
    static boolean canJump(int[] nums){int maxR=0;for(int i=0;i<nums.length;i++){if(i>maxR)return false;maxR=Math.max(maxR,i+nums[i]);}return true;}
    public static void main(String[] a){System.out.println(canJump(new int[]{2,3,1,1,4}));System.out.println(canJump(new int[]{3,2,1,0,4}));System.out.println("Greedy: track max reachable. O(n) O(1). Pattern: 'can you reach' → greedy or DP.");}
}

public class WordSearch {
    static boolean search(char[][] b,String w){for(int r=0;r<b.length;r++)for(int c=0;c<b[0].length;c++)if(dfs(b,w,r,c,0))return true;return false;}
    static boolean dfs(char[][] b,String w,int r,int c,int i){if(i==w.length())return true;if(r<0||r>=b.length||c<0||c>=b[0].length||b[r][c]!=w.charAt(i))return false;char t=b[r][c];b[r][c]='#';boolean ok=dfs(b,w,r+1,c,i+1)||dfs(b,w,r-1,c,i+1)||dfs(b,w,r,c+1,i+1)||dfs(b,w,r,c-1,i+1);b[r][c]=t;return ok;}
    public static void main(String[] a){char[][] b={{'A','B','C','E'},{'S','F','C','S'},{'A','D','E','E'}};System.out.println(search(b,"ABCCED"));System.out.println(search(b,"SEE"));System.out.println(search(b,"ABCB"));System.out.println("Backtrack: mark+recurse+restore. O(m*n*4^L).");}
}

import java.util.*;
public class Islands {
    static int count(char[][] g){int r=g.length,c=g[0].length,cnt=0;int[][] d={{0,1},{0,-1},{1,0},{-1,0}};for(int i=0;i<r;i++)for(int j=0;j<c;j++){if(g[i][j]=='1'){cnt++;Queue<int[]> q=new ArrayDeque<>();q.offer(new int[]{i,j});g[i][j]='0';while(!q.isEmpty()){int[] p=q.poll();for(int[] dd:d){int ni=p[0]+dd[0],nj=p[1]+dd[1];if(ni>=0&&ni<r&&nj>=0&&nj<c&&g[ni][nj]=='1'){g[ni][nj]='0';q.offer(new int[]{ni,nj});}}}}}return cnt;}
    public static void main(String[] a){System.out.println(count(new char[][]{{'1','1','0'},{'0','1','0'},{'0','0','1'}}));System.out.println(count(new char[][]{{'1','1','1'},{'0','1','0'},{'1','1','1'}}));System.out.println("BFS flood fill O(m*n). Pattern: connected components.");}
}

import java.util.*;
public class CC {
    static int change(int[] c,int amt){int[] dp=new int[amt+1];Arrays.fill(dp,amt+1);dp[0]=0;for(int i=1;i<=amt;i++)for(int x:c)if(x<=i)dp[i]=Math.min(dp[i],dp[i-x]+1);return dp[amt]>amt?-1:dp[amt];}
    public static void main(String[] a){System.out.println(change(new int[]{1,5,11},15));System.out.println(change(new int[]{2},3));System.out.println(change(new int[]{1,2,5},11));System.out.println("O(n*m) DP. Init dp[amt+1] not MAX_VALUE. Pattern: min cost → DP.");}
}

import java.util.*;
public class LRU {
    static class Cache{Map<Integer,Integer> m=new LinkedHashMap<>(16,0.75f,true){protected boolean removeEldestEntry(Map.Entry<Integer,Integer> e){return size()>cap;}};int cap;Cache(int c){cap=c;}int get(int k){return m.getOrDefault(k,-1);}void put(int k,int v){m.put(k,v);}}
    public static void main(String[] a){Cache c=new Cache(2);c.put(1,1);c.put(2,2);System.out.println(c.get(1));c.put(3,3);System.out.println(c.get(2));System.out.println(c.get(3));System.out.println("LinkedHashMap(16,0.75f,true) + removeEldestEntry = LRU in 5 lines. Full: HashMap+DLL O(1).");}
}

public class Rotate {
    static void rotate(int[][] m){int n=m.length;for(int i=0;i<n;i++)for(int j=i+1;j<n;j++){int t=m[i][j];m[i][j]=m[j][i];m[j][i]=t;}for(int i=0;i<n;i++){int l=0,r=n-1;while(l<r){int t=m[i][l];m[i][l]=m[i][r];m[i][r]=t;l++;r--;}}System.out.println(java.util.Arrays.deepToString(m));}
    public static void main(String[] a){rotate(new int[][]{{1,2,3},{4,5,6},{7,8,9}});System.out.println("Transpose then reverse each row. O(n²) O(1). Common in-place matrix trick.");}
}

import java.util.*;
public class Sprint {
    // Problem 1: Two Sum — 5 min target
    static int[] twoSum(int[] n,int t){Map<Integer,Integer> m=new HashMap<>();for(int i=0;i<n.length;i++){int c=t-n[i];if(m.containsKey(c))return new int[]{m.get(c),i};m.put(n[i],i);}return null;}
    // Problem 2: Max profit — 5 min target
    static int maxP(int[] p){int min=p[0],max=0;for(int i=1;i<p.length;i++){max=Math.max(max,p[i]-min);min=Math.min(min,p[i]);}return max;}
    // Problem 3: Valid parentheses — 5 min target
    static boolean valid(String s){Deque<Character> st=new ArrayDeque<>();for(char c:s.toCharArray()){if("([{".indexOf(c)>=0)st.push(c);else{if(st.isEmpty())return false;char t=st.pop();if(c==')'&&t!='('||c==']'&&t!='['||c=='}'&&t!='{')return false;}}return st.isEmpty();}
    public static void main(String[] a){System.out.println(Arrays.toString(twoSum(new int[]{2,7,11,15},9)));System.out.println(maxP(new int[]{7,1,5,3,6,4}));System.out.println(valid("()[]{}"));boolean ok=Arrays.equals(twoSum(new int[]{2,7,11,15},9),new int[]{0,1})&&maxP(new int[]{7,1,5,3,6,4})==5&&valid("()[]{}");System.out.println("All pass: "+ok);}
}
